package com.example.ecommerce.search.service;

import com.example.ecommerce.search.dto.Facet;
import com.example.ecommerce.search.dto.SearchResult;
import com.example.ecommerce.search.model.Product;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.index.query.TermQueryBuilder;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.aggregations.AggregationBuilder;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductService {

    private static final Logger logger = LoggerFactory.getLogger(ProductService.class);
    private static final String PRODUCT_INDEX = "products";
    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void init() {
        createProductIndexWithMapping();
    }

    public void createProductIndexWithMapping() {
        try {
            GetIndexRequest request = new GetIndexRequest(PRODUCT_INDEX);
            boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);

            if (!exists) {
                CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCT_INDEX);
                createIndexRequest.settings(Settings.builder()
                        .put("index.number_of_shards", 1)
                        .put("index.number_of_replicas", 0)
                );

                createIndexRequest.mapping(
                        "{\n" +
                                "  \"properties\": {\n" +
                                "    \"id\": { \"type\": \"keyword\" },\n" +
                                "    \"name\": { \"type\": \"text\", \"fields\": { \"keyword\": { \"type\": \"keyword\" } } },\n" +
                                "    \"description\": { \"type\": \"text\" },\n" +
                                "    \"price\": { \"type\": \"float\" },\n" +
                                "    \"category\": { \"type\": \"keyword\" },\n" +
                                "    \"brand\": { \"type\": \"keyword\" },\n" +
                                "    \"imageUrl\": { \"type\": \"keyword\" },\n" +
                                "    \"stock\": { \"type\": \"integer\" }\n" +
                                "  }\n" +
                                "}",
                        XContentType.JSON
                );
                client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
                logger.info("Product index created with mapping: {}", PRODUCT_INDEX);
            } else {
                logger.info("Product index already exists: {}", PRODUCT_INDEX);
            }
        } catch (IOException e) {
            logger.error("Error creating product index: {}", e.getMessage());
        }
    }

    public void deleteProductIndex() {
        try {
            DeleteIndexRequest request = new DeleteIndexRequest(PRODUCT_INDEX);
            AcknowledgedResponse deleteResponse = client.indices().delete(request, RequestOptions.DEFAULT);
            if (deleteResponse.isAcknowledged()) {
                logger.info("Product index deleted: {}", PRODUCT_INDEX);
            } else {
                logger.warn("Product index deletion not acknowledged: {}", PRODUCT_INDEX);
            }
        } catch (IOException e) {
            logger.error("Error deleting product index: {}", e.getMessage());
        }
    }

    public Product indexProduct(Product product) {
        try {
            if (product.getId() == null) {
                product.setId(UUID.randomUUID().toString()); // Generate ID if not provided
            }
            String productJson = objectMapper.writeValueAsString(product);
            IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                    .id(product.getId())
                    .source(productJson, XContentType.JSON);

            IndexResponse response = client.index(request, RequestOptions.DEFAULT);
            logger.info("Product indexed: id={}, status={}", product.getId(), response.getResult());
            return product;
        } catch (IOException e) {
            logger.error("Error indexing product {}: {}", product.getId(), e.getMessage());
            throw new RuntimeException("Failed to index product", e);
        }
    }

    public Product getProductById(String id) {
        try {
            GetRequest getRequest = new GetRequest(PRODUCT_INDEX, id);
            GetResponse getResponse = client.get(getRequest, RequestOptions.DEFAULT);

            if (getResponse.isExists()) {
                String sourceAsString = getResponse.getSourceAsString();
                return objectMapper.readValue(sourceAsString, Product.class);
            }
            return null;
        } catch (IOException e) {
            logger.error("Error retrieving product by id {}: {}", id, e.getMessage());
            throw new RuntimeException("Failed to retrieve product", e);
        }
    }

    public SearchResult searchProducts(String query, List<String> categories, List<String> brands, int page, int size) {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (query != null && !query.trim().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description"));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery()); // If no query, return all products (filtered)
        }

        if (categories != null && !categories.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", categories));
        }
        if (brands != null && !brands.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", brands));
        }

        searchSourceBuilder.query(boolQuery);

        // Pagination
        searchSourceBuilder.from(page * size);
        searchSourceBuilder.size(size);

        // Facets (Aggregations)
        AggregationBuilder categoryAggregation = AggregationBuilders.terms("categories_agg")
                .field("category.keyword")
                .size(10); // Top 10 categories
        searchSourceBuilder.aggregation(categoryAggregation);

        AggregationBuilder brandAggregation = AggregationBuilders.terms("brands_agg")
                .field("brand.keyword")
                .size(10); // Top 10 brands
        searchSourceBuilder.aggregation(brandAggregation);

        searchRequest.source(searchSourceBuilder);

        try {
            SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);
            return parseSearchResponse(searchResponse);
        } catch (IOException e) {
            logger.error("Error searching products: {}", e.getMessage());
            throw new RuntimeException("Failed to search products", e);
        }
    }

    private SearchResult parseSearchResponse(SearchResponse searchResponse) throws JsonProcessingException {
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(objectMapper.readValue(hit.getSourceAsString(), Product.class));
        }

        List<Facet> facets = new ArrayList<>();
        if (searchResponse.getAggregations() != null) {
            Terms categoriesAgg = searchResponse.getAggregations().get("categories_agg");
            if (categoriesAgg != null) {
                Map<String, Long> categoryEntries = categoriesAgg.getBuckets().stream()
                        .collect(Collectors.toMap(Terms.Bucket::getKeyAsString, Terms.Bucket::getDocCount));
                facets.add(new Facet("category", categoryEntries));
            }

            Terms brandsAgg = searchResponse.getAggregations().get("brands_agg");
            if (brandsAgg != null) {
                Map<String, Long> brandEntries = brandsAgg.getBuckets().stream()
                        .collect(Collectors.toMap(Terms.Bucket::getKeyAsString, Terms.Bucket::getDocCount));
                facets.add(new Facet("brand", brandEntries));
            }
        }

        return new SearchResult(products, searchResponse.getHits().getTotalHits().value, facets);
    }
}
