package com.example.ecommerce.search.service;

import com.example.ecommerce.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
public class SearchQueryLogService {

    private static final Logger logger = LoggerFactory.getLogger(SearchQueryLogService.class);
    private static final String SEARCH_LOG_INDEX = "search_queries";
    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public SearchQueryLogService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void init() {
        createSearchLogIndexWithMapping();
    }

    public void createSearchLogIndexWithMapping() {
        try {
            GetIndexRequest request = new GetIndexRequest(SEARCH_LOG_INDEX);
            boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);

            if (!exists) {
                CreateIndexRequest createIndexRequest = new CreateIndexRequest(SEARCH_LOG_INDEX);
                createIndexRequest.settings(Settings.builder()
                        .put("index.number_of_shards", 1)
                        .put("index.number_of_replicas", 0)
                );

                createIndexRequest.mapping(
                        "{\n" +
                                "  \"properties\": {\n" +
                                "    \"id\": { \"type\": \"keyword\" },\n" +
                                "    \"query\": { \"type\": \"text\", \"fields\": { \"keyword\": { \"type\": \"keyword\" } } },\n" +
                                "    \"timestamp\": { \"type\": \"date\" },\n" +
                                "    \"resultsCount\": { \"type\": \"long\" }\n" +
                                "  }\n" +
                                "}",
                        XContentType.JSON
                );
                client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
                logger.info("Search query log index created with mapping: {}", SEARCH_LOG_INDEX);
            } else {
                logger.info("Search query log index already exists: {}", SEARCH_LOG_INDEX);
            }
        } catch (IOException e) {
            logger.error("Error creating search query log index: {}", e.getMessage());
        }
    }

    public void deleteSearchLogIndex() {
        try {
            DeleteIndexRequest request = new DeleteIndexRequest(SEARCH_LOG_INDEX);
            AcknowledgedResponse deleteResponse = client.indices().delete(request, RequestOptions.DEFAULT);
            if (deleteResponse.isAcknowledged()) {
                logger.info("Search query log index deleted: {}", SEARCH_LOG_INDEX);
            } else {
                logger.warn("Search query log index deletion not acknowledged: {}", SEARCH_LOG_INDEX);
            }
        } catch (IOException e) {
            logger.error("Error deleting search query log index: {}", e.getMessage());
        }
    }

    public SearchQueryLog logSearchQuery(String query, long resultsCount) {
        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setQuery(query);
        log.setTimestamp(Instant.now());
        log.setResultsCount(resultsCount);

        try {
            String logJson = objectMapper.writeValueAsString(log);
            IndexRequest request = new IndexRequest(SEARCH_LOG_INDEX)
                    .id(log.getId())
                    .source(logJson, XContentType.JSON);

            IndexResponse response = client.index(request, RequestOptions.DEFAULT);
            logger.debug("Search query logged: id={}, query='{}', resultsCount={}, status={}",
                    log.getId(), log.getQuery(), log.getResultsCount(), response.getResult());
            return log;
        } catch (IOException e) {
            logger.error("Error logging search query '{}': {}", query, e.getMessage());
            throw new RuntimeException("Failed to log search query", e);
        }
    }

    public List<SearchQueryLog> getAllSearchLogs(int page, int size) {
        SearchRequest searchRequest = new SearchRequest(SEARCH_LOG_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.query(QueryBuilders.matchAllQuery());
        searchSourceBuilder.sort("timestamp", org.elasticsearch.search.sort.SortOrder.DESC); // Newest first
        searchSourceBuilder.from(page * size);
        searchSourceBuilder.size(size);
        searchRequest.source(searchSourceBuilder);

        try {
            SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);
            List<SearchQueryLog> logs = new ArrayList<>();
            for (SearchHit hit : searchResponse.getHits().getHits()) {
                logs.add(objectMapper.readValue(hit.getSourceAsString(), SearchQueryLog.class));
            }
            return logs;
        } catch (IOException e) {
            logger.error("Error retrieving all search logs: {}", e.getMessage());
            throw new RuntimeException("Failed to retrieve search logs", e);
        }
    }
}
