package com.example.ecommerce.search.controller;

import com.example.ecommerce.search.model.SearchQueryLog;
import com.example.ecommerce.search.service.SearchQueryLogService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/search-logs")
public class SearchQueryLogController {

    private final SearchQueryLogService searchQueryLogService;

    public SearchQueryLogController(SearchQueryLogService searchQueryLogService) {
        this.searchQueryLogService = searchQueryLogService;
    }

    @GetMapping
    public ResponseEntity<List<SearchQueryLog>> getAllSearchLogs(
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "10") int size) {
        List<SearchQueryLog> logs = searchQueryLogService.getAllSearchLogs(page, size);
        return ResponseEntity.ok(logs);
    }
}